import type { GridViewModel } from "@/components/grid/model";

import { borderAlphaForCell, colorsForCell } from "./colors";

export type StageRectDraw = {
  readonly key: string;
  readonly x: number;
  readonly y: number;
  readonly width: number;
  readonly height: number;
  readonly fillColor: number;
  readonly borderColor: number;
  readonly borderWidth: number;
  readonly borderAlpha: number;
  readonly alpha: number;
};

export type StageDrawList = {
  readonly width: number;
  readonly height: number;
  readonly cellSize: number;
  readonly gap: number;
  readonly padding: number;
  readonly canvasWidth: number;
  readonly canvasHeight: number;
  readonly rects: readonly StageRectDraw[];
};

const DEFAULT_CELL_SIZE = 23;
const DEFAULT_GAP = 2;
const DEFAULT_PADDING = 12;
const ENTITY_INSET = 5;

export type StageDrawListOptions = {
  readonly cellSize?: number;
  readonly gap?: number;
  readonly padding?: number;
};

/**
 * Pure function of `GridViewModel` → canvas draw instructions.
 * No Pixi, DOM, or engine imports — safe for headless determinism tests.
 */
export const createStageDrawList = (
  model: GridViewModel,
  options: StageDrawListOptions = {},
): StageDrawList => {
  const cellSize = options.cellSize ?? DEFAULT_CELL_SIZE;
  const gap = options.gap ?? DEFAULT_GAP;
  const padding = options.padding ?? DEFAULT_PADDING;
  const canvasWidth =
    padding * 2 + model.width * cellSize + Math.max(0, model.width - 1) * gap;
  const canvasHeight =
    padding * 2 + model.height * cellSize + Math.max(0, model.height - 1) * gap;
  const rects: StageRectDraw[] = [];

  for (const cell of model.cells) {
    const x = padding + cell.x * (cellSize + gap);
    const y = padding + cell.y * (cellSize + gap);
    const colors = colorsForCell(cell);

    rects.push({
      key: `${cell.key}:bg`,
      x,
      y,
      width: cellSize,
      height: cellSize,
      fillColor: colors.fill,
      borderColor: colors.border,
      borderWidth: 1,
      borderAlpha: borderAlphaForCell(cell),
      alpha: colors.alpha,
    });

    if (colors.entity !== null) {
      rects.push({
        key: `${cell.key}:entity`,
        x: x + ENTITY_INSET,
        y: y + ENTITY_INSET,
        width: cellSize - ENTITY_INSET * 2,
        height: cellSize - ENTITY_INSET * 2,
        fillColor: colors.entity,
        borderColor: colors.entity,
        borderWidth: 0,
        borderAlpha: 0,
        alpha: colors.alpha,
      });
    }
  }

  return {
    width: model.width,
    height: model.height,
    cellSize,
    gap,
    padding,
    canvasWidth,
    canvasHeight,
    rects,
  };
};

"use client";

import { useEffect, useRef } from "react";
import { Application, Graphics } from "pixi.js";

import type { StageDrawList } from "./draw-list";
import styles from "./PixiStage.module.css";

type PixiStageCanvasProps = {
  readonly drawList: StageDrawList;
};

export default function PixiStageCanvas({ drawList }: PixiStageCanvasProps) {
  const hostRef = useRef<HTMLDivElement>(null);
  const appRef = useRef<Application | null>(null);
  const graphicsRef = useRef<Graphics | null>(null);

  useEffect(() => {
    if (typeof window === "undefined") {
      return;
    }

    const host = hostRef.current;

    if (host === null) {
      return;
    }

    let disposed = false;
    const app = new Application();
    appRef.current = app;

    void (async () => {
      await app.init({
        width: drawList.canvasWidth,
        height: drawList.canvasHeight,
        background: 0x0d1117,
        antialias: false,
        resolution: 1,
        autoDensity: true,
      });

      if (disposed) {
        app.destroy(true, { children: true });
        return;
      }

      host.replaceChildren(app.canvas);
      const graphics = new Graphics();
      graphicsRef.current = graphics;
      app.stage.addChild(graphics);
      paintDrawList(graphics, drawList);
    })();

    return () => {
      disposed = true;
      graphicsRef.current = null;
      app.destroy(true, { children: true });
      appRef.current = null;
      host.replaceChildren();
    };
  }, []);

  useEffect(() => {
    const app = appRef.current;
    const graphics = graphicsRef.current;

    if (app === null || graphics === null) {
      return;
    }

    app.renderer.resize(drawList.canvasWidth, drawList.canvasHeight);
    paintDrawList(graphics, drawList);
  }, [drawList]);

  return (
    <div
      className={styles.canvasHost}
      ref={hostRef}
      data-testid="pixi-stage-canvas-host"
      aria-hidden="true"
    />
  );
}

const paintDrawList = (graphics: Graphics, drawList: StageDrawList): void => {
  graphics.clear();

  for (const rect of drawList.rects) {
    graphics.rect(rect.x, rect.y, rect.width, rect.height);
    graphics.fill({ color: rect.fillColor, alpha: rect.alpha });

    if (rect.borderWidth > 0) {
      graphics.stroke({
        color: rect.borderColor,
        width: rect.borderWidth,
        alpha: rect.borderAlpha * rect.alpha,
      });
    }
  }
};

"use client";

import dynamic from "next/dynamic";
import { useMemo, useRef } from "react";

import {
  createGridViewModel,
  type GridRenderCursor,
} from "@/components/grid/model";

import { StageA11yMirror } from "./a11y-mirror";
import { createStageDrawList } from "./draw-list";
import styles from "./PixiStage.module.css";
import type { StageProps } from "./seam";

const PixiStageCanvas = dynamic(() => import("./PixiStageCanvas"), {
  ssr: false,
  loading: () => <div className={styles.empty}>Loading canvas…</div>,
});

export function PixiStage({ state, markers = [] }: StageProps) {
  const cursorRef = useRef<GridRenderCursor | undefined>(undefined);
  const model = useMemo(() => {
    if (state === null) {
      return null;
    }

    const nextModel = createGridViewModel(state, cursorRef.current, markers);
    cursorRef.current = nextModel.cursor;

    return nextModel;
  }, [state, markers]);

  const drawList = useMemo(
    () => (model === null ? null : createStageDrawList(model)),
    [model],
  );

  if (model === null || drawList === null || model.width === 0 || model.height === 0) {
    return (
      <div className={styles.stage} data-testid="pixi-stage">
        <div className={styles.empty}>No floor grid</div>
      </div>
    );
  }

  return (
    <div className={styles.stage} data-testid="pixi-stage">
      <PixiStageCanvas drawList={drawList} />
      <StageA11yMirror model={model} />
    </div>
  );
}

import { createElement } from "react";
import { renderToStaticMarkup } from "react-dom/server";
import { describe, expect, it } from "vitest";

import {
  createFogMixGridFixtureState,
  createMidActionGridFixtureState,
  createPrecedenceFixtureState,
} from "@/components/grid/fixtures";
import { createGridViewModel } from "@/components/grid/model";

import { StageA11yMirror } from "./a11y-mirror";
import { createStageDrawList } from "./draw-list";

describe("PixiStage draw-list seam", () => {
  it("maps every grid cell to deterministic background rects", () => {
    const model = createGridViewModel(createFogMixGridFixtureState());
    const drawList = createStageDrawList(model);

    expect(drawList.width).toBe(5);
    expect(drawList.height).toBe(3);
    expect(drawList.rects.filter((rect) => rect.key.endsWith(":bg"))).toHaveLength(
      15,
    );
    expect(drawList.canvasWidth).toBe(
      drawList.padding * 2 +
        drawList.width * drawList.cellSize +
        (drawList.width - 1) * drawList.gap,
    );
  });

  it("adds entity overlay rects only for visible entity layers", () => {
    const model = createGridViewModel(createPrecedenceFixtureState());
    const drawList = createStageDrawList(model);
    const entityRects = drawList.rects.filter((rect) =>
      rect.key.endsWith(":entity"),
    );

    expect(entityRects).toHaveLength(5);
    expect(
      drawList.rects.find((rect) => rect.key === "0:0:entity")?.fillColor,
    ).toBe(0xffe680);
    expect(
      drawList.rects.find((rect) => rect.key === "1:0:entity")?.fillColor,
    ).toBe(0xff7474);
  });

  it("is a pure function of the view-model", () => {
    const model = createGridViewModel(createMidActionGridFixtureState());
    const first = createStageDrawList(model);
    const second = createStageDrawList(model);

    expect(second).toEqual(first);
  });
});

describe("PixiStage a11y mirror", () => {
  it("mirrors the DOM grid aria structure off-screen", () => {
    const model = createGridViewModel(createFogMixGridFixtureState());
    const markup = renderToStaticMarkup(
      createElement(StageA11yMirror, { model }),
    );

    expect(markup).toContain('role="grid"');
    expect(markup).toContain('aria-rowcount="3"');
    expect(markup).toContain('aria-colcount="5"');
    expect(markup.match(/role="gridcell"/g)?.length).toBe(15);
    expect(markup).toContain('aria-label="1,1 you"');
    expect(markup).toContain('data-testid="stage-a11y-mirror"');
  });
});

import type { GameState } from "@engine/state";

import type {
  GridOverlayMarker,
  GridViewModel,
} from "@/components/grid/model";

/**
 * Frozen render seam (phase63-v1).
 *
 * App wiring passes `StageProps` to either the DOM grid (`surface: "dom"`) or the
 * Pixi canvas stage (`surface: "pixi"`). Both surfaces consume the same
 * `GridViewModel` produced from `GameState`; neither mutates engine state.
 */
export const STAGE_RENDER_SEAM_VERSION = "phase63-v1" as const;

export type StageSurface = "dom" | "pixi";

/** Props the app layer hands to any stage renderer. */
export type StageProps = {
  readonly state: GameState | null;
  readonly markers?: readonly GridOverlayMarker[];
  readonly glyphSizeRem?: number;
};

/** Renderer selection at the seam boundary. */
export type StageRendererProps = StageProps & {
  readonly surface?: StageSurface;
};

/** Pure canvas draw input — shared by Pixi and headless tests. */
export type StageCanvasInput = {
  readonly model: GridViewModel;
  readonly glyphSizeRem?: number;
};

import {
  GLYPH_TRAP,
  defaultVisibleFog,
  floorKnowledge,
  fogFromState,
  gridFromState,
  render,
} from "@engine/render";
import type {
  EntityId,
  EntityInstance,
  GameState,
  Position,
  SerializableRecord,
} from "@engine/state";

export type GridFogState = "visible" | "remembered" | "unseen";

export type GridLayer =
  | "player"
  | "enemy"
  | "npc"
  | "item"
  | "trap"
  | "terrain"
  | "empty";

export type GridShape =
  | "none"
  | "circle"
  | "diamond"
  | "square"
  | "dot"
  | "triangle";

export type GridPulseKind = "damage" | "heal";

export type GridPulse = {
  readonly id: string;
  readonly kind: GridPulseKind;
  readonly text: string;
};

export type GridMotion = {
  readonly dx: number;
  readonly dy: number;
};

export type GridOverlayMarker = {
  readonly id: string;
  readonly x: number;
  readonly y: number;
  readonly label: string;
  readonly tone: "quest";
};

export type GridCellView = {
  readonly key: string;
  readonly x: number;
  readonly y: number;
  readonly glyph: string;
  readonly terrain: string;
  readonly fog: GridFogState;
  readonly layer: GridLayer;
  readonly featureKind: string;
  readonly featureId: string;
  readonly hasItem: boolean;
  readonly label: string;
  readonly badge: string;
  readonly shape: GridShape;
  readonly markers: readonly GridOverlayMarker[];
  readonly pulses: readonly GridPulse[];
  readonly hitFlash: boolean;
  readonly motion: GridMotion | null;
  readonly renderKey: string;
};

export type GridRenderCursor = {
  readonly runId: string;
  readonly floorId: string;
  readonly logLength: number;
};

export type GridViewModel = {
  readonly width: number;
  readonly height: number;
  readonly cells: readonly GridCellView[];
  readonly rows: readonly (readonly GridCellView[])[];
  readonly cursor: GridRenderCursor;
};

type CellEffects = {
  readonly pulses: readonly GridPulse[];
  readonly hitFlash: boolean;
  readonly motion: GridMotion | null;
};

type MutableCellEffects = {
  pulses: GridPulse[];
  hitFlash: boolean;
  motion: GridMotion | null;
};

type RuntimeLogEvent = {
  readonly turn?: unknown;
  readonly type?: unknown;
  readonly data?: unknown;
};

type RuntimeRecord = {
  readonly [key: string]: unknown;
};

type GridFeatureView = {
  readonly id: string;
  readonly kind: string;
  readonly name: string;
  readonly x: number;
  readonly y: number;
};

const EMPTY_EFFECTS: CellEffects = {
  pulses: [],
  hitFlash: false,
  motion: null,
};

const ENTITY_KIND_ORDER: Readonly<Record<EntityInstance["kind"], number>> = {
  enemy: 0,
  item: 1,
  npc: 2,
  trap: 3,
};

export const hasRenderableGrid = (state: GameState): boolean =>
  renderedGridLines(state).length > 0;

export const createGridViewModel = (
  state: GameState,
  previousCursor?: GridRenderCursor,
  markers: readonly GridOverlayMarker[] = [],
): GridViewModel => {
  const lines = renderedGridLines(state);
  const width = lines[0]?.length ?? 0;
  const height = lines.length;
  const cursor = cursorForState(state);
  const grid = gridFromState(state);
  const entitiesByPosition = entitiesByCell(state);
  const featuresByPosition = featuresByCell(state);
  const fogStates = fogStatesForState(state, width, height);
  const effectsByPosition = effectsSinceLastRender(state, previousCursor);
  const markersByPosition = overlayMarkersByCell(markers);
  const cells: GridCellView[] = [];

  for (let y = 0; y < height; y += 1) {
    const line = lines[y] ?? "";

    for (let x = 0; x < width; x += 1) {
      const glyph = line.charAt(x) || " ";
      const positionKey = keyForPosition({ x, y });
      const fog = fogStates[y * width + x] ?? "unseen";
      const entities = entitiesByPosition.get(positionKey) ?? [];
      const layer = layerAt(
        state,
        { x, y },
        glyph,
        fog,
        entities,
      );
      const terrain = terrainAt(grid, width, height, x, y);
      const effects = effectsByPosition.get(positionKey) ?? EMPTY_EFFECTS;
      const feature = fog === "unseen"
        ? null
        : featuresByPosition.get(positionKey) ?? null;
      cells.push(
        createCell({
          x,
          y,
          glyph,
          terrain,
          fog,
          layer,
          feature,
          hasItem: entities.some((entity) => entity.kind === "item"),
          markers: markersByPosition.get(positionKey) ?? [],
          effects,
        }),
      );
    }
  }

  return {
    width,
    height,
    cells,
    rows: rowsForCells(cells, width),
    cursor,
  };
};

const renderedGridLines = (state: GameState): readonly string[] => {
  const lines = render(state).split("\n");

  return lines.length > 1 ? lines.slice(0, -1) : [];
};

const cursorForState = (state: GameState): GridRenderCursor => ({
  runId: state.run.runId,
  floorId: state.floor.floorId,
  logLength: state.log.length,
});

const rowsForCells = (
  cells: readonly GridCellView[],
  width: number,
): readonly (readonly GridCellView[])[] => {
  if (width <= 0) {
    return [];
  }

  const rows: GridCellView[][] = [];

  for (let offset = 0; offset < cells.length; offset += width) {
    rows.push(cells.slice(offset, offset + width));
  }

  return rows;
};

const createCell = ({
  x,
  y,
  glyph,
  terrain,
  fog,
  layer,
  feature,
  hasItem,
  markers,
  effects,
}: {
  readonly x: number;
  readonly y: number;
  readonly glyph: string;
  readonly terrain: string;
  readonly fog: GridFogState;
  readonly layer: GridLayer;
  readonly feature: GridFeatureView | null;
  readonly hasItem: boolean;
  readonly markers: readonly GridOverlayMarker[];
  readonly effects: CellEffects;
}): GridCellView => {
  const affordance = affordanceForLayer(layer);

  return {
    key: `${x}:${y}`,
    x,
    y,
    glyph,
    terrain,
    fog,
    layer,
    featureKind: feature?.kind ?? "",
    featureId: feature?.id ?? "",
    hasItem,
    label: labelForLayer(layer, fog),
    badge: affordance.badge,
    shape: affordance.shape,
    markers,
    pulses: effects.pulses,
    hitFlash: effects.hitFlash,
    motion: effects.motion,
    renderKey: [
      glyph,
      terrain,
      fog,
      layer,
      feature?.kind ?? "",
      feature?.id ?? "",
      hasItem ? "item" : "",
      affordance.badge,
      affordance.shape,
      effects.hitFlash ? "hit" : "",
      effects.motion === null
        ? ""
        : `${effects.motion.dx},${effects.motion.dy}`,
      ...markers.map((marker) => `marker:${marker.id}:${marker.tone}`),
      ...effects.pulses.map((pulse) => `${pulse.id}:${pulse.kind}:${pulse.text}`),
    ].join("|"),
  };
};

const terrainAt = (
  grid: ReturnType<typeof gridFromState>,
  width: number,
  height: number,
  x: number,
  y: number,
): string => {
  if (
    grid === null ||
    grid.width !== width ||
    grid.height !== height
  ) {
    return "";
  }

  const tile = grid.tiles[y * width + x];
  return typeof tile?.terrain === "string" ? tile.terrain : "";
};

const overlayMarkersByCell = (
  markers: readonly GridOverlayMarker[],
): ReadonlyMap<string, readonly GridOverlayMarker[]> => {
  const grouped = new Map<string, GridOverlayMarker[]>();

  for (const marker of markers) {
    const key = keyForPosition(marker);
    const existing = grouped.get(key);

    if (existing === undefined) {
      grouped.set(key, [marker]);
    } else {
      existing.push(marker);
    }
  }

  return grouped;
};

const featuresByCell = (
  state: GameState,
): ReadonlyMap<string, GridFeatureView> => {
  const grouped = new Map<string, GridFeatureView>();

  for (const feature of decorativeFeatures(state)) {
    grouped.set(keyForPosition(feature), feature);
  }

  return grouped;
};

const decorativeFeatures = (state: GameState): readonly GridFeatureView[] => {
  const opaque = asRecord(state.floor.geometry.opaque);
  const knowledge = asRecord(opaque?.knowledge);
  const features = knowledge?.decorativeFeatures;

  if (!Array.isArray(features)) {
    return [];
  }

  return features.flatMap((feature: SerializableRecord) => {
    const parsed = parseFeature(feature);
    return parsed === null ? [] : [parsed];
  });
};

const parseFeature = (feature: SerializableRecord): GridFeatureView | null => {
  const record = asRecord(feature);
  const id = stringValue(record?.id);

  const id = stringValue(record?.id);
  const kind = stringValue(record?.kind);
  const name = stringValue(record?.name);
  const x = numberValue(record?.x);
  const y = numberValue(record?.y);

  if (id === null || kind === null || name === null || x === null || y === null) {
    return null;
  }

  return { id, kind, name, x, y };
};

const affordanceForLayer = (
  layer: GridLayer,
): { readonly badge: string; readonly shape: GridShape } => {
  switch (layer) {
    case "player":
      return { badge: "YOU", shape: "circle" };
    case "enemy":
      return { badge: "FOE", shape: "diamond" };
    case "npc":
      return { badge: "NPC", shape: "square" };
    case "item":
      return { badge: "ITM", shape: "dot" };
    case "trap":
      return { badge: "TRP", shape: "triangle" };
    case "terrain":
    case "empty":
      return { badge: "", shape: "none" };
  }
};

const labelForLayer = (layer: GridLayer, fog: GridFogState): string => {
  if (fog === "unseen") {
    return "unseen";
  }

  if (fog === "remembered") {
    return "remembered terrain";
  }

  switch (layer) {
    case "player":
      return "you";
    case "enemy":
      return "enemy";
    case "npc":
      return "npc";
    case "item":
      return "item";
    case "trap":
      return "revealed trap";
    case "terrain":
      return "terrain";
    case "empty":
      return "empty";
  }
};

const layerAt = (
  state: GameState,
  position: Position,
  glyph: string,
  fog: GridFogState,
  entities: readonly EntityInstance[],
): GridLayer => {
  if (fog === "unseen" || glyph === " ") {
    return "empty";
  }

  if (fog === "remembered") {
    return "terrain";
  }

  if (samePosition(state.player.position, position)) {
    return "player";
  }

  if (entities.some((entity) => entity.kind === "enemy")) {
    return "enemy";
  }

  if (entities.some((entity) => entity.kind === "npc")) {
    return "npc";
  }

  if (entities.some((entity) => entity.kind === "item")) {
    return "item";
  }

  if (entities.some((entity) => entity.kind === "trap") && glyph === GLYPH_TRAP) {
    return "trap";
  }

  return "terrain";
};

const entitiesByCell = (
  state: GameState,
): ReadonlyMap<string, readonly EntityInstance[]> => {
  const grouped = new Map<string, EntityInstance[]>();
  const entities = Object.values(state.entities).sort(compareEntities);

  for (const entity of entities) {
    const key = keyForPosition(entity.position);
    const existing = grouped.get(key);

    if (existing === undefined) {
      grouped.set(key, [entity]);
    } else {
      existing.push(entity);
    }
  }

  return grouped;
};

const compareEntities = (
  left: EntityInstance,
  right: EntityInstance,
): number => {
  const kindDelta = ENTITY_KIND_ORDER[left.kind] - ENTITY_KIND_ORDER[right.kind];

  if (kindDelta !== 0) {
    return kindDelta;
  }

  return compareEntityIds(left.id, right.id);
};

const compareEntityIds = (left: EntityId, right: EntityId): number => {
  const parsedLeft = parseEntityId(left);
  const parsedRight = parseEntityId(right);
  const kindOrder = parsedLeft.kind.localeCompare(parsedRight.kind);

  return kindOrder === 0
    ? parsedLeft.index - parsedRight.index
    : kindOrder;
};

const parseEntityId = (
  id: EntityId,
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10),
  };
};

const fogStatesForState = (
  state: GameState,
  width: number,
  height: number,
): readonly GridFogState[] => {
  const count = width * height;

  if (count <= 0) {
    return [];
  }

  const grid = gridFromState(state);

  if (
    grid === null ||
    grid.width !== width ||
    grid.height !== height ||
    grid.tiles.length !== count
  ) {
    return Array.from({ length: count }, () => "visible");
  }

  if (floorKnowledge(state).mapRevealed === true) {
    return Array.from({ length: count }, () => "visible");
  }

  const fog = fogFromState(state, grid) ?? defaultVisibleFog(grid);

  return fog.tiles.map((tile) => {
    switch (tile.state) {
      case "visible":
      case "remembered":
      case "unseen":
        return tile.state;
      default:
        return "unseen";
    }
  });
};

const effectsSinceLastRender = (
  state: GameState,
  previousCursor?: GridRenderCursor,
): ReadonlyMap<string, CellEffects> => {
  const cursor = cursorForState(state);
  const canDiff =
    previousCursor !== undefined &&
    previousCursor.runId === cursor.runId &&
    previousCursor.floorId === cursor.floorId &&
    previousCursor.logLength <= cursor.logLength;

  if (!canDiff) {
    return new Map();
  }

  const events = (state.log as readonly RuntimeLogEvent[]).slice(
    previousCursor.logLength,
  );

  if (events.length === 0) {
    return new Map();
  }

  const positionsByActorId = actorPositions(state);
  const effectsByPosition = new Map<string, MutableCellEffects>();

  events.forEach((event, eventIndex) => {
    applyPulseEvent(event, eventIndex, positionsByActorId, effectsByPosition);
    applyMovementEvent(event, positionsByActorId, effectsByPosition);
  });

  return new Map(
    [...effectsByPosition.entries()].map(([key, effects]) => [
      key,
      {
        pulses: effects.pulses,
        hitFlash: effects.hitFlash,
        motion: effects.motion,
      },
    ]),
  );
};

const applyPulseEvent = (
  event: RuntimeLogEvent,
  eventIndex: number,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
): void => {
  const data = asRecord(event.data);
  const eventId = `${String(event.turn ?? "t")}:${String(event.type)}:${eventIndex}`;

  switch (event.type) {
    case "attack_hit": {
      const defenderId = stringValue(data?.defenderId);
      const damage = numberValue(data?.damage);

      if (defenderId !== null && damage !== null && damage > 0) {
        addPulseForActor(
          defenderId,
          positionsByActorId,
          effectsByPosition,
          {
            id: eventId,
            kind: "damage",
            text: `-${damage}`,
          },
        );
      }
      break;
    }
    case "status_tick": {
      const entityId = stringValue(data?.entityId);
      const hpDelta = numberValue(data?.hpDelta);

      if (entityId !== null && hpDelta !== null && hpDelta !== 0) {
        addPulseForActor(
          entityId,
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpDelta),
        );
      }
      break;
    }
    case "starvation": {
      const hpBefore = numberValue(data?.hpBefore);
      const hpAfter = numberValue(data?.hpAfter);

      if (hpBefore !== null && hpAfter !== null && hpAfter !== hpBefore) {
        addPulseForActor(
          "player",
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
    case "level_up": {
      const hpBefore = numberValue(data?.currentHpBefore);
      const hpAfter = numberValue(data?.currentHpAfter);

      if (hpBefore !== null && hpAfter !== null && hpAfter !== hpBefore) {
        addPulseForActor(
          "player",
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
    case "effect_executed": {
      const verb = stringValue(data?.verb);
      const targetId = stringValue(data?.targetId);
      const details = asRecord(data?.details);
      const hpBefore = numberValue(details?.hpBefore);
      const hpAfter = numberValue(details?.hpAfter);

      if (
        targetId !== null &&
        hpBefore !== null &&
        hpAfter !== null &&
        hpAfter !== hpBefore &&
        (verb === "damage" || verb === "heal")
      ) {
        addPulseForActor(
          targetId,
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
  }
};

const applyMovementEvent = (
  event: RuntimeLogEvent,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
): void => {
  if (event.type !== "moved" && event.type !== "enemy_moved") {
    return;
  }

  const data = asRecord(event.data);
  const actorId = stringValue(data?.actorId);
  const from = positionValue(data?.from);
  const to = positionValue(data?.to) ?? (actorId === null
    ? null
    : positionsByActorId.get(actorId) ?? null);

  if (from === null || to === null) {
    return;
  }

  const effects = mutableEffectsAt(effectsByPosition, to);
  effects.motion = {
    dx: from.x - to.x,
    dy: from.y - to.y,
  };
};

const pulseForDelta = (id: string, delta: number): GridPulse => ({
  id,
  kind: delta < 0 ? "damage" : "heal",
  text: `${delta > 0 ? "+" : ""}${delta}`,
});

const addPulseForActor = (
  actorId: string,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
  pulse: GridPulse,
): void => {
  const position = positionsByActorId.get(actorId);

  if (position === undefined) {
    return;
  }

  const effects = mutableEffectsAt(effectsByPosition, position);
  effects.pulses.push(pulse);

  if (pulse.kind === "damage") {
    effects.hitFlash = true;
  }
};

const mutableEffectsAt = (
  effectsByPosition: Map<string, MutableCellEffects>,
  position: Position,
): MutableCellEffects => {
  const key = keyForPosition(position);
  const existing = effectsByPosition.get(key);

  if (existing !== undefined) {
    return existing;
  }

  const created: MutableCellEffects = {
    pulses: [],
    hitFlash: false,
    motion: null,
  };
  effectsByPosition.set(key, created);

import {
  rasterizeSpriteManifest,
  type RasterizedSprite,
  type SpriteManifest
} from "./sprite-manifest.js";

export const FALLBACK_THEME_ID = "fallback";

export type SpriteAtlasThemeId = string | typeof FALLBACK_THEME_ID;

export type SpriteAtlasKey = {
  readonly themeId: SpriteAtlasThemeId;
  readonly entityId: string;
  readonly seed: string;
};

export type SpriteAtlasEntry = {
  readonly key: SpriteAtlasKey;
  readonly keyString: string;
  readonly manifest: SpriteManifest;
  readonly raster: RasterizedSprite;
};

export const spriteAtlasKey = (
  themeId: SpriteAtlasThemeId,
  entityId: string,
  seed: string
): SpriteAtlasKey => ({ themeId, entityId, seed });

export const serializeSpriteAtlasKey = (key: SpriteAtlasKey): string =>
  [key.themeId, key.entityId, key.seed].map(encodeKeyPart).join("|");

export const parseSpriteAtlasKey = (keyString: string): SpriteAtlasKey => {
  const parts = keyString.split("|");
  if (parts.length !== 3) {
    throw new Error(`invalid sprite atlas key: ${keyString}`);
  }

  const [themeId, entityId, seed] = parts.map(decodeKeyPart);
  if (
    themeId === undefined ||
    entityId === undefined ||
    seed === undefined ||
    themeId.length === 0 ||
    entityId.length === 0 ||
    seed.length === 0
  ) {
    throw new Error(`invalid sprite atlas key: ${keyString}`);
  }

  return { themeId, entityId, seed };
};

export class SpriteAtlasCache {
  readonly #entries = new Map<string, SpriteAtlasEntry>();

  get size(): number {
    return this.#entries.size;
  }

  has(key: SpriteAtlasKey): boolean {
    return this.#entries.has(serializeSpriteAtlasKey(key));
  }

  get(key: SpriteAtlasKey): SpriteAtlasEntry | null {
    return this.#entries.get(serializeSpriteAtlasKey(key)) ?? null;
  }

  set(
    key: SpriteAtlasKey,
    manifest: SpriteManifest,
    options: { readonly scale?: number } = {}
  ): SpriteAtlasEntry {
    const keyString = serializeSpriteAtlasKey(key);
    const entry = {
      key,
      keyString,
      manifest,
      raster: rasterizeSpriteManifest(manifest, options)
    } as const satisfies SpriteAtlasEntry;

    this.#entries.set(keyString, entry);

    return entry;
  }

  getOrSet(
    key: SpriteAtlasKey,
    manifest: SpriteManifest,
    options: { readonly scale?: number } = {}
  ): SpriteAtlasEntry {
    const existing = this.get(key);

    return existing ?? this.set(key, manifest, options);
  }

  entries(): readonly SpriteAtlasEntry[] {
    return [...this.#entries.values()].sort((left, right) =>
      left.keyString.localeCompare(right.keyString)
    );
  }

  clear(): void {
    this.#entries.clear();
  }
}

const encodeKeyPart = (part: string): string => encodeURIComponent(part);

const decodeKeyPart = (part: string): string => decodeURIComponent(part);

import { FALLBACK_THEME_ID } from "./atlas.js";
import {
  formatSpriteValidationErrors,
  validateSpriteManifest,
  type SpriteManifest
} from "./sprite-manifest.js";

export const FALLBACK_SPRITE_SET_VERSION = "everdeep.art-fallback.v1";

export const FALLBACK_SPRITE_IDS = [
  "terrain.floor",
  "terrain.wall",
  "terrain.door",
  "terrain.stairs_down",
  "terrain.entrance",
  "terrain.water",
  "trap.hidden",
  "trap.revealed",
  "actor.player",
  "enemy.brute",
  "enemy.skirmisher",
  "enemy.caster",
  "item.gear",
  "item.consumable",
  "item.treasure",
  "npc.keeper",
  "feature.hoard"
] as const;

export type FallbackSpriteId = (typeof FALLBACK_SPRITE_IDS)[number];

export type FallbackSpriteRole =
  | "terrain"
  | "trap"
  | "player"
  | "enemy"
  | "item"
  | "npc"
  | "feature";

export type FallbackSpriteRecord = {
  readonly id: FallbackSpriteId;
  readonly role: FallbackSpriteRole;
  readonly label: string;
  readonly manifest: SpriteManifest;
};

export type FallbackSpriteSet = {
  readonly version: typeof FALLBACK_SPRITE_SET_VERSION;
  readonly themeId: typeof FALLBACK_THEME_ID;
  readonly sprites: readonly FallbackSpriteRecord[];
};

export type FallbackSpriteSetValidationResult =
  | {
      readonly ok: true;
      readonly spriteSet: FallbackSpriteSet;
    }
  | {
      readonly ok: false;
      readonly errors: readonly string[];
    };

export const parseFallbackSpriteSet = (
  value: unknown
): FallbackSpriteSetValidationResult => {
  const errors: string[] = [];

  if (!isPlainObject(value)) {
    return { ok: false, errors: ["<root>: fallback set must be an object"] };
  }

  if (value.version !== FALLBACK_SPRITE_SET_VERSION) {
    errors.push(
      `version: expected ${FALLBACK_SPRITE_SET_VERSION}, got ${String(
        value.version
      )}`
    );
  }

  if (value.themeId !== FALLBACK_THEME_ID) {
    errors.push(`themeId: expected ${FALLBACK_THEME_ID}`);
  }

  if (!Array.isArray(value.sprites)) {
    errors.push("sprites: must be an array");
  }

  const seen = new Set<string>();
  const sprites: FallbackSpriteRecord[] = [];

  if (Array.isArray(value.sprites)) {
    value.sprites.forEach((sprite, index) => {
      if (!isPlainObject(sprite)) {
        errors.push(`sprites[${index}]: sprite must be an object`);
        return;
      }

      const id = sprite.id;
      const role = sprite.role;
      const label = sprite.label;

      if (!isFallbackSpriteId(id)) {
        errors.push(`sprites[${index}].id: unknown fallback sprite id`);
        return;
      }

      if (seen.has(id)) {
        errors.push(`sprites[${index}].id: duplicate fallback sprite id ${id}`);
        return;
      }
      seen.add(id);

      if (!isFallbackSpriteRole(role)) {
        errors.push(`sprites[${index}].role: unknown fallback sprite role`);
        return;
      }

      if (typeof label !== "string" || label.length === 0) {
        errors.push(`sprites[${index}].label: label must be non-empty`);
        return;
      }

      const validated = validateSpriteManifest(sprite.manifest);
      if (!validated.ok) {
        errors.push(
          `sprites[${index}].manifest: ${formatSpriteValidationErrors(
            validated.errors
          )}`
        );
        return;
      }

      sprites.push({
        id,
        role,
        label,
        manifest: validated.manifest
      });
    });
  }

  for (const requiredId of FALLBACK_SPRITE_IDS) {
    if (!seen.has(requiredId)) {
      errors.push(`sprites: missing required fallback sprite ${requiredId}`);
    }
  }

  if (errors.length > 0) {
    return { ok: false, errors };
  }

  return {
    ok: true,
    spriteSet: {
      version: FALLBACK_SPRITE_SET_VERSION,
      themeId: FALLBACK_THEME_ID,
      sprites
    }
  };
};

export const fallbackSpriteById = (
  spriteSet: FallbackSpriteSet,
  id: FallbackSpriteId
): FallbackSpriteRecord => {
  const sprite = spriteSet.sprites.find((candidate) => candidate.id === id);

  if (sprite === undefined) {
    throw new Error(`missing fallback sprite ${id}`);
  }

  return sprite;
};

export const fallbackSpritesById = (
  spriteSet: FallbackSpriteSet
): ReadonlyMap<FallbackSpriteId, FallbackSpriteRecord> =>
  new Map(spriteSet.sprites.map((sprite) => [sprite.id, sprite]));

const FALLBACK_SPRITE_ID_SET = new Set<string>(FALLBACK_SPRITE_IDS);

const FALLBACK_SPRITE_ROLES = [
  "terrain",
  "trap",
  "player",
  "enemy",
  "item",
  "npc",
  "feature"
] as const satisfies readonly FallbackSpriteRole[];

const FALLBACK_SPRITE_ROLE_SET = new Set<string>(FALLBACK_SPRITE_ROLES);

const isFallbackSpriteId = (value: unknown): value is FallbackSpriteId =>
  typeof value === "string" && FALLBACK_SPRITE_ID_SET.has(value);

const isFallbackSpriteRole = (value: unknown): value is FallbackSpriteRole =>
  typeof value === "string" && FALLBACK_SPRITE_ROLE_SET.has(value);

const isPlainObject = (
  value: unknown
): value is { readonly [key: string]: unknown } =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

