/**
 * Mirrors the CI check job's vitest sequence locally:
 * typecheck → lint → root vitest → every vitest.config.ts under tests/ and app/.
 */
import { spawnSync } from "node:child_process";
import { readdirSync } from "node:fs";
import { join, relative, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(fileURLToPath(new URL("..", import.meta.url)));
const ROOT_VITEST_CONFIG = resolve(root, "vitest.config.ts");

function discoverVitestConfigs(dir) {
  const configs = [];

  function walk(current) {
    for (const entry of readdirSync(current, { withFileTypes: true })) {
      const full = join(current, entry.name);
      if (entry.isDirectory()) {
        walk(full);
      } else if (entry.name === "vitest.config.ts") {
        configs.push(full);
      }
    }
  }

  walk(dir);
  return configs;
}

function runStep(label, command, args) {
  console.log(`\n=== ${label} ===`);
  const result = spawnSync(command, args, {
    cwd: root,
    stdio: "inherit",
    shell: false,
  });
  const ok = result.status === 0;
  console.log(`${ok ? "PASS" : "FAIL"}: ${label}`);
  return ok;
}

const discovered = [
  ...discoverVitestConfigs(join(root, "tests")),
  ...discoverVitestConfigs(join(root, "app")),
]
  .map((configPath) => resolve(configPath))
  .filter((configPath) => configPath !== ROOT_VITEST_CONFIG)
  .sort();

console.log("Discovered vitest configs:");
for (const configPath of discovered) {
  console.log(`  - ${relative(root, configPath)}`);
}

const results = [];
const baseSteps = [
  ["typecheck", "pnpm", ["run", "typecheck"]],
  ["lint", "pnpm", ["run", "lint"]],
  ["root vitest", "pnpm", ["exec", "vitest", "run"]],
];

for (const [label, command, args] of baseSteps) {
  const ok = runStep(label, command, args);
  results.push({ label, ok });
  if (!ok) {
    break;
  }
}

if (results.every((step) => step.ok)) {
  for (const configPath of discovered) {
    const rel = relative(root, configPath);
    const label = `vitest: ${rel}`;
    const ok = runStep(label, "pnpm", ["exec", "vitest", "run", "--config", rel]);
    results.push({ label, ok });
    if (!ok) {
      break;
    }
  }
}

console.log("\n=== Summary ===");
for (const { label, ok } of results) {
  console.log(`${ok ? "PASS" : "FAIL"}: ${label}`);
}

const allOk = results.length > 0 && results.every((step) => step.ok);
console.log(allOk ? "\nAll steps passed." : "\nOne or more steps failed.");
process.exit(allOk ? 0 : 1);

export const Terrain = {
  Floor: "floor",
  Wall: "wall",
  Door: "door",
  Water: "water",
  StairsDown: "stairs_down",
  Entrance: "entrance",
} as const;

export type TerrainKind = (typeof Terrain)[keyof typeof Terrain];

export type DoorState = "open" | "closed";

export type Tile = {
  readonly terrain: TerrainKind;
  readonly door: DoorState | null;
};

export const TERRAIN_KINDS = [
  Terrain.Floor,
  Terrain.Wall,
  Terrain.Door,
  Terrain.Water,
  Terrain.StairsDown,
  Terrain.Entrance,
] as const satisfies readonly TerrainKind[];

export const TERRAIN_WALKABLE = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: true,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const TERRAIN_TRANSPARENT = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: false,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const createTile = (
  terrain: TerrainKind,
  door: DoorState | null = null,
): Tile => ({
  terrain,
  door: terrain === Terrain.Door ? (door ?? "closed") : null,
});

export const cloneTile = (tile: Tile): Tile => ({
  terrain: tile.terrain,
  door: tile.terrain === Terrain.Door ? (tile.door ?? "closed") : null,
});

export const isWalkableTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_WALKABLE[terrain];

export const isTransparentTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_TRANSPARENT[terrain];

export const isWalkableTile = (tile: Tile): boolean =>
  TERRAIN_WALKABLE[tile.terrain];

export const isTransparentTile = (tile: Tile): boolean => {
  if (tile.terrain === Terrain.Door) {
    return tile.door === "open";
  }

  return TERRAIN_TRANSPARENT[tile.terrain];
};

